RAW.trim().split('\n').forEach((line,idx)=>{
  if(!line)return;
  const p=line.split('|');
  if(p.length<5)return;
  const file=p[0],author=p[1],license=p[2],licenseUrl=p[3],pageUrl=p[4];
  window.IMAGE_ATTRIB_REGISTRY[file]={author,license,licenseUrl,pageUrl,source:'Wikimedia Commons',title:file,idx:idx+1};
});
